    def sync_open_register(self, cash_register: dict):
        """
        Sube la caja abierta a Firestore (doc 'caja_activa/current').
        Llamar cuando el admin abre la caja.
        """
        if not self.enabled:
            return
        def _do():
            try:
                self.db.collection('caja_activa').document('current').set({
                    'id':             cash_register.get('id'),
                    'initial_amount': cash_register.get('initial_amount', 0),
                    'opening_date':   cash_register.get('opening_date', datetime.now().isoformat()),
                    'notes':          cash_register.get('notes', ''),
                    'status':         'open',
                    'updated_at':     datetime.now().isoformat(),
                })
                logger.info(f"Firebase: Caja #{cash_register.get('id')} abierta y subida.")
            except Exception as e:
                logger.error(f"Firebase: Error subiendo apertura de caja: {e}")
        self._run(_do)

    def sync_close_register(self):
        """
        Marca la caja activa como cerrada en Firestore.
        Llamar cuando el admin cierra la caja.
        """
        if not self.enabled:
            return
        def _do():
            try:
                self.db.collection('caja_activa').document('current').set({
                    'status':     'closed',
                    'updated_at': datetime.now().isoformat(),
                }, merge=True)
                logger.info("Firebase: Caja marcada como cerrada.")
            except Exception as e:
                logger.error(f"Firebase: Error cerrando caja en Firebase: {e}")
        self._run(_do)

    def get_active_register(self) -> Optional[dict]:
        """
        Descarga la caja activa desde Firestore.
        Retorna el dict con id, initial_amount, opening_date, status o None.
        """
        if not self.enabled:
            return None
        try:
            doc = self.db.collection('caja_activa').document('current').get()
            if doc.exists:
                data = doc.to_dict()
                if data.get('status') == 'open':
                    return data
            return None
        except Exception as e:
            logger.error(f"Firebase: Error descargando caja activa: {e}")
            return None

    def ensure_local_register(self, db_manager) -> Optional[int]:
        """
        Descarga la caja activa de Firebase y la crea/reutiliza en la DB local.
        Retorna el ID de la caja local, o None si no hay caja activa en Firebase.
        """
        if not self.enabled:
            return None
        try:
            remote = self.get_active_register()
            if not remote:
                return None
            remote_id = remote.get('id')
            # Ver si ya existe localmente
            existing = db_manager.execute_query(
                "SELECT id FROM cash_register WHERE id = ? AND status = 'open'",
                (remote_id,)
            )
            if existing:
                logger.info(f"Firebase: Caja #{remote_id} ya existe localmente.")
                return remote_id
            # Crear la caja local con el mismo ID para que las ventas se vinculen
            try:
                db_manager.execute_update(
                    "INSERT OR REPLACE INTO cash_register (id, initial_amount, opening_date, status, notes) VALUES (?, ?, ?, 'open', ?)",
                    (remote_id, remote.get('initial_amount', 0), remote.get('opening_date', datetime.now().isoformat()), remote.get('notes', ''))
                )
                logger.info(f"Firebase: Caja #{remote_id} creada localmente desde Firebase.")
                return remote_id
            except Exception as e:
                logger.error(f"Firebase: Error creando caja local: {e}")
                return None
        except Exception as e:
            logger.error(f"Firebase: Error en ensure_local_register: {e}")
            return None

